import React, { useEffect } from 'react';
import './Hero.css';

const Hero = ({ 
  title = "WEB", 
  subtitle = "DEVELOPER", 
  backgroundImage = "https://upload.wikimedia.org/wikipedia/commons/c/c5/Moraine_Lake_17092005.jpg",
  scrollTarget = "#content",
  typingStrings = ["DESIGNER", "DEVELOPER", "CREATIVE"]
}) => {
  useEffect(() => {
    // Load jQuery and Typed.js if not already loaded
    const loadScripts = () => {
      if (typeof window.$ === 'undefined') {
        const jqueryScript = document.createElement('script');
        jqueryScript.src = 'https://code.jquery.com/jquery-3.6.0.min.js';
        jqueryScript.onload = () => {
          const typedScript = document.createElement('script');
          typedScript.src = 'https://cdn.jsdelivr.net/npm/typed.js@2.0.12';
          typedScript.onload = () => {
            initializeTyping();
            initializeScrollButton();
          };
          document.head.appendChild(typedScript);
        };
        document.head.appendChild(jqueryScript);
      } else {
        initializeTyping();
        initializeScrollButton();
      }
    };

    const initializeTyping = () => {
      if (window.$ && window.Typed) {
        window.$(".p2").typed({
          strings: typingStrings,
          typeSpeed: 50,
          backSpeed: 10,
          backDelay: 2000,
          showCursor: false,
          loop: false
        });
      }
    };

    const initializeScrollButton = () => {
      if (window.$) {
        // Smooth scroll functionality
        window.$('a[href*="#"]:not([href="#"])').click(function() {
          if (location.pathname.replace(/^\//, '') == this.pathname.replace(/^\//, '') && location.hostname == this.hostname) {
            const target = window.$(this.hash);
            const targetElement = target.length ? target : window.$('[name=' + this.hash.slice(1) + ']');
            if (targetElement.length) {
              window.$('html,body').animate({
                scrollTop: targetElement.offset().top
              }, 1000);
              return false;
            }
          }
        });

        // Button animation
        window.$('.hero-down').mousedown(function() {
          if (window.TweenMax) {
            window.TweenMax.fromTo('.btn-react', 0.25, {
              opacity: 0,
              scale: 0
            }, {
              opacity: 0.25,
              scale: 1,
              onComplete: function() {
                window.TweenMax.to('.btn-react', 0.25, {
                  opacity: 0,
                  scale: 0
                });
              }
            });
          }
        });
      }
    };

    loadScripts();
  }, [typingStrings]);

  return (
    <section 
      className="hero" 
      style={{ 
        backgroundImage: `url(${backgroundImage})`,
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        backgroundRepeat: 'no-repeat'
      }}
    >
      <div className="inner-text">
        <p className="p1">{title}</p>
        <p className="p2">{subtitle}</p>
      </div>
      <a className="hero-down" href={scrollTarget}>
        <div className="btn-react"></div>
        <i className="fa fa-chevron-down"></i>
      </a>
    </section>
  );
};

export default Hero;
